import { NextRequest, NextResponse } from 'next/server';
import { google } from 'googleapis';
import { Readable } from 'stream';

// ストリーム変換用のヘルパー関数
function bufferToStream(buffer: Buffer) {
  const stream = new Readable();
  stream.push(buffer);
  stream.push(null);
  return stream;
}

export async function POST(req: NextRequest) {
  try {
    // 1. フロントから送られてきたデータを受け取る
    const formData = await req.formData();
    const file = formData.get('file') as File;
    const folderName = formData.get('folderName') as string; // 例: "Client_1001/R5"

    if (!file) {
      return NextResponse.json({ error: 'ファイルがありません' }, { status: 400 });
    }

    // 2. Google Driveの認証（サービスアカウント）
    // ※本番では .env に書いた鍵を使います
    // const auth = new google.auth.GoogleAuth({
    //   credentials: JSON.parse(process.env.GOOGLE_SERVICE_ACCOUNT_KEY!),
    //   scopes: ['https://www.googleapis.com/auth/drive'],
    // });
    // const drive = google.drive({ version: 'v3', auth });

    // ★MVP用モック: 実際には保存せず、成功したフリをする
    // （GCPの設定が終わったらここを本物のコードに差し替えます）
    console.log(`[Mock Upload] Saving ${file.name} to Folder: ${folderName}`);
    
    // 擬似的な待機時間
    await new Promise(resolve => setTimeout(resolve, 1500));

    return NextResponse.json({ 
      success: true, 
      fileId: 'mock_google_drive_id_12345',
      name: file.name
    });

  } catch (error) {
    console.error('Upload Error:', error);
    return NextResponse.json({ error: '保存に失敗しました' }, { status: 500 });
  }
}